import React, { createContext, useContext, useState, useEffect } from 'react';
import { useAuth } from './AuthContext';

const NotificationContext = createContext();

export function useNotifications() {
  return useContext(NotificationContext);
}

export function NotificationProvider({ children }) {
  const [notifications, setNotifications] = useState([]);
  const { user } = useAuth();

  const addNotification = (message, type = 'info', duration = 5000) => {
    const id = Date.now() + Math.random();
    const notification = {
      id,
      message,
      type, // 'success', 'error', 'warning', 'info'
      duration
    };

    setNotifications(prev => [...prev, notification]);

    // Auto remove after duration
    if (duration > 0) {
      setTimeout(() => {
        removeNotification(id);
      }, duration);
    }

    return id;
  };

  const removeNotification = (id) => {
    setNotifications(prev => prev.filter(notif => notif.id !== id));
  };

  const clearAllNotifications = () => {
    setNotifications([]);
  };

  // Check for various app events and show notifications
  useEffect(() => {
    if (!user) return;

    const checkForNotifications = () => {
      // Welcome notification for new users
      const hasSeenWelcome = localStorage.getItem(`welcome-seen-${user._id}`);
      if (!hasSeenWelcome) {
        setTimeout(() => {
          addNotification(
            `Welcome back, ${user.name}! Ready to manage your finances?`,
            'success'
          );
          localStorage.setItem(`welcome-seen-${user._id}`, 'true');
        }, 1000);
      }

      // Check for goals that are close to completion
      // This would typically come from an API call, but for demo purposes:
      setTimeout(() => {
        addNotification(
          '💡 Tip: Track your expenses daily to stay within budget!',
          'info'
        );
      }, 3000);

      // Simulate budget alert (in real app, this would check actual budget data)
      setTimeout(() => {
        addNotification(
          '⚠️ You\'ve used 80% of your monthly budget. Consider reviewing your expenses.',
          'warning'
        );
      }, 5000);
    };

    checkForNotifications();
  }, [user]);

  // Expose addNotification globally for use in components
  useEffect(() => {
    window.showNotification = addNotification;
    return () => {
      delete window.showNotification;
    };
  }, []);

  const value = {
    notifications,
    addNotification,
    removeNotification,
    clearAllNotifications
  };

  return (
    <NotificationContext.Provider value={value}>
      {children}
    </NotificationContext.Provider>
  );
}

export { NotificationContext };
